 17→const frontendVersion = "0.1.0"
 18→const frontendLanguage = "go"
 19→
 20→// Handler processes protocol requests and writes responses.
 21→type Handler struct {
 22→	reader           *bufio.Scanner
 23→	writer           io.Writer
 24→	log              *slog.Logger
 25→	lastAnalyzedFile string // remembered from the most recent analyze command
 26→	registry         *generators.Registry
 27→}
 28→
 29→// NewHandler creates a handler reading from r, writing responses to w,
 30→// and logging to logw at the level set by SHATTER_LOG_LEVEL.
 31→func NewHandler(r io.Reader, w io.Writer, logw io.Writer) *Handler {
 32→	scanner := bufio.NewScanner(r)
 33→	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024) // 10MB max line
 34→	return &Handler{
 35→		reader:   scanner,
 36→		writer:   w,
 37→		log:      slog.New(newPrefixHandler(logw, slogLevelFromEnv())),
 38→		registry: generators.NewRegistry(),
 39→	}
 40→}
 41→
 42→// NewHandlerWithLogLevel creates a handler with an explicit log level (for testing).
 43→func NewHandlerWithLogLevel(r io.Reader, w io.Writer, logw io.Writer, level string) *Handler {
 44→	scanner := bufio.NewScanner(r)
 45→	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024)
 46→	return &Handler{
 47→		reader:   scanner,
 48→		writer:   w,
 49→		log:      slog.New(newPrefixHandler(logw, slogLevelFromString(level))),
 50→		registry: generators.NewRegistry(),
 51→	}
 52→}
 53→
 54→// Run processes requests until shutdown or EOF. Returns nil on clean shutdown.
 55→func (h *Handler) Run() error {
 56→	h.log.Debug("Starting Go frontend", "protocol", ProtocolVersion)
 57→
 58→	for h.reader.Scan() {
 59→		line := h.reader.Text()
 60→		if line == "" {
 61→			continue
 62→		}
 63→
 64→		h.log.Log(context.Background(), LevelTrace, "Received", "raw", line)
 65→
 66→		var req Request
 67→		if err := json.Unmarshal([]byte(line), &req); err != nil {
 68→			h.log.Log(context.Background(), LevelTrace, "Failed to parse request", "err", err)
 69→			continue
 70→		}
 71→
 72→		resp, shutdown := h.dispatch(req)
 73→		if err := h.send(resp); err != nil {
 74→			return fmt.Errorf("writing response: %w", err)
 75→		}
 76→
 77→		if shutdown {
 78→			h.log.Debug("Shutting down")
 79→			return nil
 80→		}
 81→	}
 82→
 83→	if err := h.reader.Err(); err != nil {
 84→		return fmt.Errorf("reading stdin: %w", err)
 85→	}
 86→
 87→	h.log.Debug("Stdin closed, exiting")
 88→	return nil
 89→}
