132→func (h *Handler) handleHandshake(resp Response, req Request) Response {
133→	resp.Status = "handshake"
134→	resp.FrontendVersion = frontendVersion
135→	resp.Language = frontendLanguage
136→	caps := make([]string, len(CommandCapabilities))
137→	copy(caps, CommandCapabilities)
138→	caps = append(caps,
139→		"complex_type:date", "complex_type:duration", "complex_type:url",
140→		"complex_type:reg_exp", "complex_type:ip_address", "complex_type:big_int",
141→		"complex_type:rational", "complex_type:big_decimal", "complex_type:error",
142→	)
143→	resp.Capabilities = caps
144→	return resp
145→}
