195→func (h *Handler) handleInstrument(resp Response, req Request) Response {
196→	if req.File == "" {
197→		resp.Status = "error"
198→		resp.Code = ErrInvalidRequest
199→		resp.Message = "instrument command requires a file path"
200→		return resp
201→	}
202→
203→	if _, err := os.Stat(req.File); err != nil {
204→		resp.Status = "error"
205→		resp.Code = ErrFileNotFound
206→		resp.Message = fmt.Sprintf("file not found: %s", req.File)
207→		return resp
208→	}
209→
210→	h.lastAnalyzedFile = req.File
211→
212→	outputDir, err := instrument.InstrumentFile(req.File, req.Function, req.ProjectRoot)
213→	if err != nil {
214→		resp.Status = "error"
215→		resp.Code = ErrInternalError
216→		resp.Message = fmt.Sprintf("instrumentation failed: %v", err)
217→		return resp
218→	}
219→
220→	instrumented := true
221→	resp.Status = "instrument"
222→	resp.Instrumented = &instrumented
223→	resp.OutputFile = &outputDir
224→	return resp
225→}
