227→func (h *Handler) handleExecute(resp Response, req Request) Response {
228→	file := req.File
229→	if file == "" {
230→		file = h.lastAnalyzedFile
231→	}
232→	if file == "" {
233→		resp.Status = "error"
234→		resp.Code = ErrInvalidRequest
235→		resp.Message = "execute command requires a file path (or a prior analyze)"
236→		return resp
237→	}
238→
239→	if req.Function == nil || *req.Function == "" {
240→		resp.Status = "error"
241→		resp.Code = ErrInvalidRequest
242→		resp.Message = "execute command requires a function name"
243→		return resp
244→	}
245→
246→	if _, err := os.Stat(file); err != nil {
247→		resp.Status = "error"
248→		resp.Code = ErrFileNotFound
249→		resp.Message = fmt.Sprintf("file not found: %s", file)
250→		return resp
251→	}
252→
253→	// Convert protocol MockConfigs to instrument MockConfigs and pass to executor.
254→	var execMocks []instrument.MockConfig
255→	for _, m := range req.Mocks {
256→		execMocks = append(execMocks, instrument.MockConfig{
257→			Symbol:           m.Symbol,
258→			ReturnValues:     m.ReturnValues,
259→			ShouldTrackCalls: m.ShouldTrackCalls,
260→			DefaultBehavior:  m.DefaultBehavior,
261→		})
262→	}
263→	result, err := instrument.ExecuteFunction(file, *req.Function, req.Inputs, execMocks)
264→	if err != nil {
265→		resp.Status = "error"
266→		if strings.Contains(err.Error(), "function not found") {
267→			resp.Code = "function_not_found"
268→		} else if strings.Contains(err.Error(), "build failed") {
269→			resp.Code = "instrumentation_failed"
270→		} else if strings.Contains(err.Error(), "timed out") {
271→			resp.Code = ErrExecutionTimeout
272→		} else {
273→			resp.Code = ErrInternalError
274→		}
275→		resp.Message = err.Error()
276→		return resp
277→	}
278→
279→	resp.Status = "execute"
280→	resp.ReturnValue = result.ReturnValue
281→	resp.ThrownError = convertErrorInfo(result.ThrownError)
282→	resp.LinesExecuted = toIntSlice(result.LinesExecuted)
283→	resp.BranchPath = convertBranchPath(result.BranchPath)
284→	resp.PathConstraints = extractPathConstraints(result.BranchPath)
285→	resp.CallsToExternal = convertExternalCalls(result.ExternalCalls)
286→	resp.SideEffects = convertSideEffects(result.SideEffects)
287→	resp.ScopeEvents = result.ScopeEvents
288→	resp.Performance = &PerfMetrics{
289→		WallTimeMs:         result.Performance.WallTimeMs,
290→		CPUTimeUs:          result.Performance.CPUTimeUs,
291→		HeapUsedBytes:      result.Performance.HeapUsedBytes,
292→		HeapAllocatedBytes: result.Performance.HeapAllocatedBytes,
293→	}
294→
295→	return resp
296→}
