340→func extractPathConstraints(branches []instrument.BranchDecision) []SymConstraint {
341→	var constraints []SymConstraint
342→	for _, b := range branches {
343→		if b.ConstraintJSON == "" {
344→			continue
345→		}
346→		var sc SymConstraint
347→		if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
348→			constraints = append(constraints, sc)
349→		}
350→	}
351→	if constraints == nil {
352→		return []SymConstraint{}
353→	}
354→	return constraints
355→}
