357→// convertExternalCalls converts executor ExternalCall records to protocol format.
358→func convertExternalCalls(calls []instrument.ExternalCall) []ExternalCall {
359→	if len(calls) == 0 {
360→		return []ExternalCall{}
361→	}
362→	result := make([]ExternalCall, len(calls))
363→	for i, c := range calls {
364→		var args []any
365→		if c.Args != nil {
366→			json.Unmarshal(c.Args, &args) //nolint:errcheck
367→		}
368→		var retVal any
369→		if c.ReturnValue != nil {
370→			json.Unmarshal(c.ReturnValue, &retVal) //nolint:errcheck
371→		}
372→		result[i] = ExternalCall{
373→			Symbol:      c.Symbol,
374→			Args:        args,
375→			ReturnValue: retVal,
376→		}
377→	}
378→	return result
379→}
380→
381→// convertSideEffects converts executor SideEffects to protocol format.
382→func convertSideEffects(effects []instrument.SideEffect) []SideEffect {
383→	if len(effects) == 0 {
384→		return []SideEffect{}
385→	}
386→	result := make([]SideEffect, len(effects))
387→	for i, e := range effects {
388→		result[i] = SideEffect{
389→			Kind:    e.Kind,
390→			Level:   e.Level,
391→			Message: e.Message,
392→		}
393→	}
394→	return result
395→}
