411→func (h *Handler) handleGenerate(resp Response, req Request) Response {
412→	if req.File == "" {
413→		resp.Status = "error"
414→		resp.Code = ErrInvalidRequest
415→		resp.Message = "generate command requires a file path"
416→		return resp
417→	}
418→	if req.Name == "" {
419→		resp.Status = "error"
420→		resp.Code = ErrInvalidRequest
421→		resp.Message = "generate command requires a name"
422→		return resp
423→	}
424→
425→	var recipe json.RawMessage
426→	if req.Recipe != nil {
427→		recipe = *req.Recipe
428→	}
429→
430→	value, generatorID, outRecipe, err := h.registry.Generate(req.File, req.Name, recipe)
431→	if err != nil {
432→		resp.Status = "error"
433→		resp.Code = ErrInternalError
434→		resp.Message = fmt.Sprintf("generate failed: %v", err)
435→		return resp
436→	}
437→
438→	resp.Status = "generate"
439→	valCopy := json.RawMessage(value)
440→	resp.Value = &valCopy
441→	resp.GeneratorID = generatorID
442→	if outRecipe != nil {
443→		recipeCopy := json.RawMessage(outRecipe)
444→		resp.Recipe = &recipeCopy
445→	}
446→	return resp
447→}
