449→// Registry returns the generator registry, allowing custom builds to register
450→// native generators before calling Run().
451→func (h *Handler) Registry() *generators.Registry {
452→	return h.registry
453→}
454→
455→func (h *Handler) handleShutdown(resp Response) Response {
456→	h.registry.Close()
457→	resp.Status = "shutdown_ack"
458→	return resp
459→}
